parameters.jsCode:
const response = $input.first().json;

// Extract text from Gemini response
let text = '';
try {
  text = response.candidates[0].content.parts[0].text || '{}';
} catch (e) {
  throw new Error('Gemini não retornou resposta válida: ' + JSON.stringify(response));
}

// Clean JSON (remove markdown fences if present)
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

// Parse JSON
let dados;
try {
  dados = JSON.parse(text);
} catch (e) {
  throw new Error('Resposta da IA não é JSON válido: ' + text.slice(0, 200));
}

// Get original input from webhook
const input = $('Receber Invoice').first().json;

return [{
  json: {
    userId: input.userId,
    fileName: input.fileName,
    mimeType: input.mimeType,
    storagePath: input.storagePath || '',
    dadosExtraidos: dados,
    startTime: input.startTime || Date.now()
  }
}];
